// n8n Code node — filter + format review packet
// Inputs: n2 (pending rows), n3 (acked rows)

const pendingItems = $('Fetch eom_review_needed').all();
const ackedItems   = $('Fetch eom_acked').all();

const pending = Array.isArray(pendingItems[0]?.json) ? pendingItems[0].json : [];
const acked   = Array.isArray(ackedItems[0]?.json)   ? ackedItems[0].json   : [];

// Collect acked packet_ids
const ackedIds = new Set();
for (const r of acked) {
  for (const t of (r.tags || [])) {
    const m = t.match(/^eom_packet_id-(.+)$/);
    if (m) ackedIds.add(m[1]);
  }
}

const TTL_MS = 4 * 60 * 60 * 1000; // 4 hours
const now = Date.now();

for (const row of pending) {
  const tags = row.tags || [];
  let packetId = null, taskId = null, owner = 'unknown';
  for (const t of tags) {
    const mp = t.match(/^eom_packet_id-(.+)$/);
    if (mp) packetId = mp[1];
    const mt = t.match(/^task-(.+)$/);
    if (mt) taskId = mt[1];
    const mo = t.match(/^owner-(.+)$/);
    if (mo) owner = mo[1];
  }
  if (!packetId) continue;
  if (ackedIds.has(packetId)) continue;

  const created = new Date(row.created_at).getTime();
  if (now - created > TTL_MS) continue; // expired

  // Extract fields from decision_text for compact packet
  const body = row.decision_text || '';
  const objMatch  = body.match(/objective:\s*(.+?)(?:\s*\||$)/i);
  const decMatch  = body.match(/decision:\s*(.+?)(?:\s*\||$)/i);
  const objective = objMatch  ? objMatch[1].trim()  : '(see task)';
  const decision  = decMatch  ? decMatch[1].trim()  : 'review and approve or add constraints';

  const expiresAt = new Date(created + TTL_MS).toISOString().replace('.000', '');
  const ageMin = Math.round((now - created) / 60000);

  const packetText = [
    `EOM REVIEW REQUEST — routed by n8n ${new Date().toISOString()}`,
    `owner=${owner}  task_id=${taskId || 'unknown'}  packet_id=${packetId}`,
    `expires_at=${expiresAt}  age=${ageMin}m`,
    '',
    'OBJECTIVE',
    objective,
    '',
    'REQUIRED DECISION',
    decision,
    '',
    '---',
    'Full context: query MCP for eom_packet_id-' + packetId,
  ].join('\n');

  return [{ json: {
    found: true,
    packetId,
    taskId:     taskId || 'unknown',
    owner,
    expiresAt,
    ageMin,
    packetText,
    mcpRowId: row.id,
  }}];
}

return [{ json: { found: false, reason: 'no_unacked_pending_within_ttl' } }];

// No-op: log skip for debug visibility
console.log('EOM watcher: no pending review this cycle');
return [{ json: { skipped: true } }];
